    // ── Tuple and destructuring tests ───────────────────────────

    #[test]
    fn test_tuple_destructuring() {
        let out = transpile_str("fn f() { let (a, b) = pair; }");
        assert!(out.contains("auto [a, b] = pair;"));
    }

    #[test]
    fn test_tuple_destructuring_void_expr_falls_back_to_static_cast_void() {
        // Constructor calls without template args (e.g., Vec::new_()) have incomplete
        // types in C++ and can't be used in structured bindings. We fall back to
        // static_cast<void> to preserve side effects while avoiding invalid C++.
        let out = transpile_str("fn f() { let (a, b) = Vec::new_(); }");
        // Should NOT emit "auto [a, b] = Vec::new_();" (invalid C++ - CTAD failure)
        assert!(!out.contains("auto [a, b] = Vec::new_()"));
        // Should emit static_cast<void> to handle the incomplete type
        assert!(out.contains("static_cast<void>(Vec::new_())"));
    }

    #[test]
    fn test_forward_reference_uses_explicit_type_not_auto() {
        // When `let x = y;` references `y` before `y` is declared, we can't use
        // `auto x = y;` in C++ because `y` isn't defined yet. Instead, we use the
        // pre-scanned placeholder hint to emit an explicit type: `int32_t x = y;`.
        let out = transpile_str("fn f() { let x = y; let y = 5; }");
        // Should NOT emit `auto x = y;` (forward reference, invalid C++)
        assert!(!out.contains("auto x = y"));
        // Should emit explicit type for x based on y's type
        assert!(out.contains("int32_t x = y") || out.contains("auto y = 5"));
        // y should still be declared as auto (it's defined before being used)
        assert!(out.contains("auto y = 5") || out.contains("int32_t y = 5"));
    }

    #[test]
    fn test_non_copy_struct_uses_std_move_in_assignment() {
        // For non-Copy types (structs containing Vec, String, etc.), std::move should
        // be inserted in assignments to ensure the move constructor is called instead
        // of the copy constructor (which may be deleted/invalid).
        let out = transpile_str(
            "struct Foo { x: Vec<i32> } fn f() { let foo = Foo { x: Vec::new_() }; let foo2 = foo; }",
        );
        // foo2 = foo should use std::move, not copy
        assert!(out.contains("std::move(foo)"));
        // Should NOT have bare `foo` without std::move in the assignment
        assert!(!out.contains("foo2 = foo;") || out.contains("foo2 = std::move"));
    }

    #[test]
    fn test_ok_variant_with_struct_const_uses_clone_not_move() {
        // Struct const values like VersionReq::STAR are associated const lvalues in C++.
        // `std::move(const T)` still binds to copy; use `rusty::clone(...)` instead.
        let out = transpile_str(
            "struct VersionReq { comparators: Vec<i32> } impl VersionReq { pub const STAR: Self = VersionReq { comparators: Vec::new() }; } fn from_str(s: &str) -> Result<VersionReq, ()> { Ok(VersionReq::STAR) }",
        );
        assert!(
            out.contains("rusty::clone(VersionReq::STAR)"),
            "Expected rusty::clone(VersionReq::STAR) but got:\n{}",
            out
        );
        assert!(!out.contains("std::move(VersionReq::STAR)"));
    }

    #[test]
    fn test_returning_struct_const_uses_clone_not_move() {
        let out = transpile_str(
            "struct VersionReq { comparators: Vec<i32> } impl VersionReq { pub const STAR: Self = VersionReq { comparators: Vec::new() }; fn default_() -> VersionReq { VersionReq::STAR } }",
        );
        assert!(out.contains("return rusty::clone(VersionReq::STAR);"));
    }

