    #[test]
    fn test_leaf4154333333381_self_field_access_avoids_shadowing_in_next_and_drop() {
        let out = transpile_str(
            r#"
            struct IntoIter { index: usize, len: usize }
            impl IntoIter {
                fn next(&mut self) -> Option<usize> {
                    if self.index == self.len {
                        None
                    } else {
                        unsafe {
                            let index = self.index;
                            self.index = index + 1;
                            Some(index)
                        }
                    }
                }
            }
            impl Drop for IntoIter {
                fn drop(&mut self) {
                    let index = self.index;
                    let len = self.len;
                    let _keep = (index, len);
                }
            }
            "#,
        );
        assert!(
            out.contains("const auto index = this->index;")
                || out.contains("auto index = this->index;")
        );
        assert!(out.contains("this->index = index + 1;"));
        assert!(
            out.contains("const auto len = this->len;") || out.contains("auto len = this->len;")
        );
        assert!(!out.contains("const auto index = index;"));
    }

