    #[test]
    fn test_leaf221_use_cpp_import_is_classified_as_foreign_module_import() {
        let file: syn::File = syn::parse_file("use cpp::std;").expect("parse file");
        let mut cg = CodeGen::new();
        cg.emit_file(&file, None);

        assert!(
            cg.output
                .contains("// C++ module import (reserved cpp::): std")
        );
        assert!(!cg.output.contains("// TODO: external crate 'cpp'"));
        assert!(!cg.output.contains("\nusing cpp::std;"));
        assert_eq!(
            cg.cpp_module_import_bindings.get("std").map(String::as_str),
            Some("std")
        );
        assert_eq!(cg.cpp_module_import_paths, vec!["std".to_string()]);
    }

    #[test]
    fn test_leaf221_use_cpp_alias_import_records_alias_binding() {
        let file: syn::File = syn::parse_file("use cpp::std as cpp_std;").expect("parse file");
        let mut cg = CodeGen::new();
        cg.emit_file(&file, None);

        assert!(
            cg.output
                .contains("// C++ module import (reserved cpp::): std as cpp_std")
        );
        assert!(!cg.output.contains("// TODO: external crate 'cpp'"));
        assert!(!cg.output.contains("\nusing cpp_std = cpp::std;"));
        assert_eq!(
            cg.cpp_module_import_bindings
                .get("cpp_std")
                .map(String::as_str),
            Some("std")
        );
        assert_eq!(cg.cpp_module_import_paths, vec!["std".to_string()]);
    }

    #[test]
    fn test_leaf223_cpp_module_imports_emit_deduped_sorted_cxx_imports() {
        let out = transpile_str_module(
            r#"
            use cpp::zeta;
            use cpp::alpha::beta;
            use cpp::zeta as cpp_zeta;
            pub fn f() {}
        "#,
            "my_crate",
        );

        assert_eq!(out.matches("import alpha.beta;").count(), 1);
        assert_eq!(out.matches("import zeta;").count(), 1);
        assert!(!out.contains("import alpha::beta;"));

        let alpha_pos = out
            .find("import alpha.beta;")
            .expect("alpha import should be emitted");
        let zeta_pos = out
            .find("import zeta;")
            .expect("zeta import should be emitted");
        assert!(
            alpha_pos < zeta_pos,
            "imports should be deterministic and sorted: {out}"
        );
    }

