    #[test]
    fn test_namespace_function_collision_rename() {
        // When a module name collides with a function name, the namespace
        // should be renamed to avoid C++ name lookup shadowing.
        let out = transpile_str(
            r#"
            mod parser {
                pub fn from_str(input: &str) -> i32 { 0 }
                pub fn to_writer(flags: i32) -> String { String::new() }
            }
            mod tests {
                mod parser {
                    mod from_str {
                        fn valid() {}
                        fn invalid() {}
                    }
                    mod to_writer {
                        fn cases() {}
                    }
                }
            }
            "#,
        );
        // The inner test sub-modules should be renamed to avoid collision
        assert!(
            out.contains("namespace from_str_tests"),
            "from_str module should be renamed to from_str_tests\nGot: {out}"
        );
        assert!(
            out.contains("namespace to_writer_tests"),
            "to_writer module should be renamed to to_writer_tests\nGot: {out}"
        );
        // The outer function should still use its original name
        assert!(
            out.contains("from_str("),
            "outer from_str function should keep its name\nGot: {out}"
        );
    }

    #[test]
    fn test_namespace_collision_absolute_path_qualification() {
        // When calling a function from a parent module whose name is shadowed
        // by a same-named namespace in the current scope, the transpiler
        // should emit absolute path qualification.
        let out = transpile_str(
            r#"
            mod parser {
                pub fn from_str<B>(input: &str) -> i32 { 0 }
                pub fn to_writer(flags: i32, s: &mut String) {}
            }
            mod tests {
                mod parser {
                    fn roundtrip() {
                        let s = String::new();
                        to_writer(42, &mut s);
                    }
                    mod from_str {
                        fn valid() {
                            let r = from_str::<i32>("hello");
                        }
                    }
                }
            }
            "#,
        );
        // Inside tests::parser, calls to from_str/to_writer should use
        // absolute paths to avoid shadowing by the inner parser namespace
        assert!(
            out.contains("::parser::to_writer(") || out.contains("::parser::to_writer<"),
            "to_writer call inside tests::parser should use absolute path\nGot: {out}"
        );
    }

