    #[test]
    fn test_self_referential_const_deferred_for_indirect_reference() {
        // When a struct has a const whose type contains Self in a template
        // argument (e.g., `std::span<const Flag<Self>>`), the initializer
        // must be deferred outside the class body to avoid incomplete type.
        let out = transpile_str(
            r#"
            struct Flag<B> {
                name: &'static str,
                value: B,
            }
            struct MyFlags(u8);
            impl MyFlags {
                const A: MyFlags = MyFlags(1);
                const FLAGS: &'static [Flag<Self>] = &[
                    Flag { name: "A", value: MyFlags::A },
                ];
            }
            impl std::ops::BitOr for MyFlags {
                type Output = Self;
                fn bitor(self, rhs: Self) -> Self { MyFlags(self.0 | rhs.0) }
            }
            "#,
        );
        // FLAGS should be deferred (declared in-class, defined after class body)
        assert!(
            out.contains("static const") && out.contains("FLAGS;"),
            "FLAGS should have a declaration inside the class\nGot: {out}"
        );
        assert!(
            out.contains("inline const") && out.contains("MyFlags::FLAGS"),
            "FLAGS should have a deferred definition after class body\nGot: {out}"
        );
    }

    #[test]
    fn test_leaf1054010_deferred_flags_definition_emits_after_dependent_consts() {
        let out = transpile_str(
            r#"
            struct Flag<B> {
                name: &'static str,
                value: B,
            }
            struct MyFlags(u8);
            impl MyFlags {
                const FLAGS: &'static [Flag<Self>] = &[
                    Flag { name: "ABC", value: MyFlags::ABC },
                ];
                const A: MyFlags = MyFlags(1);
                const ABC: MyFlags = MyFlags(MyFlags::A.0 | (1 << 1));
            }
            impl std::ops::BitOr for MyFlags {
                type Output = Self;
                fn bitor(self, rhs: Self) -> Self { MyFlags(self.0 | rhs.0) }
            }
            "#,
        );
        let abc_pos = out
            .find("MyFlags::ABC =")
            .expect("missing ABC deferred definition");
        let flags_pos = out
            .find("MyFlags::FLAGS =")
            .expect("missing FLAGS deferred definition");
        assert!(
            abc_pos < flags_pos,
            "dependent const values should be emitted before FLAGS deferred initializer\nGot:\n{}",
            out
        );
    }

    #[test]
    fn test_closure_tuple_destructuring_uses_body_binding() {
        // C++ doesn't allow structured bindings as lambda parameters.
        // |(a, b)| a + b → [&](auto&& _destruct_param0) { auto&& [a, b] = _destruct_param0; return a + b; }
        let out = transpile_str(
            r#"
            fn f() {
                let pairs = vec![(1, 2)];
                let result: Vec<i32> = pairs.iter().map(|(a, b)| a + b).collect();
            }
            "#,
        );
        // Should NOT have structured bindings in lambda parameters
        assert!(
            !out.contains("(auto ["),
            "tuple destructuring should NOT be in lambda parameter position\nGot: {out}"
        );
        // Should have a body-level binding
        assert!(
            out.contains("_destruct_param") || out.contains("[a, b]"),
            "tuple destructuring should use body-level structured binding\nGot: {out}"
        );
    }

    #[test]
    fn test_self_ufcs_method_call_converted_to_dot_call() {
        // `Type::method(self)` inside an impl method should become
        // `(*this).method()` (dot call), not `Type::method((*this))` (static call).
        let out = transpile_str(
            r#"
            struct Flags(u8);
            impl Flags {
                fn bits(&self) -> u8 { self.0 }
                fn get_bits(&self) -> u8 {
                    Flags::bits(self)
                }
            }
            "#,
        );
        assert!(
            out.contains("(*this).bits()"),
            "Flags::bits(self) should become (*this).bits()\nGot: {out}"
        );
        assert!(
            !out.contains("Flags::bits((*this))"),
            "Should NOT emit static UFCS call\nGot: {out}"
        );
    }

